361 KnownFPClass KnownFPClass::fma(const KnownFPClass &KnownLHS,
362                                const KnownFPClass &KnownRHS,
363                                const KnownFPClass &KnownAddend,
364                                DenormalMode Mode) {
365   KnownFPClass Mul = fmul(KnownLHS, KnownRHS, Mode);
366 
367   // FMA differs from the base fmul + fadd handling only in the treatment of -0
368   // results.
369   //
370   // If the multiply is a -0 due to rounding, the final -0 + 0 will be -0,
371   // unlike for a separate fadd.
372   return fadd_impl(Mul, KnownAddend, Mode);
373 }
374 
375 KnownFPClass KnownFPClass::fma_square(const KnownFPClass &KnownSquared,
376                                       const KnownFPClass &KnownAddend,
377                                       DenormalMode Mode) {
378   KnownFPClass Squared = square(KnownSquared, Mode);
379   KnownFPClass Known = fadd_impl(Squared, KnownAddend, Mode);
380 
381   // Since we know the squared input must be positive, the add of opposite sign
382   // infinities nan hazard only applies for negative inf.
383   //
384   // TODO: Alternatively to proving addend is not -inf, we could know Squared is
385   // not pinf. Other than the degenerate always-subnormal input case, we can't
386   // prove that without a known range.
387   if (KnownAddend.isKnownNever(fcNegInf | fcNan) && Squared.isKnownNever(fcNan))
388     Known.knownNot(fcNan);
389 
390   return Known;
391 }
