393 KnownFPClass KnownFPClass::exp(const KnownFPClass &KnownSrc) {
394   KnownFPClass Known;
395   Known.knownNot(fcNegative);
396 
397   Known.propagateNaN(KnownSrc);
398 
399   if (KnownSrc.cannotBeOrderedLessThanZero()) {
400     // If the source is positive this cannot underflow.
401     Known.knownNot(fcPosZero);
402 
403     // Cannot introduce denormal values.
404     Known.knownNot(fcPosSubnormal);
405   }
406 
407   // If the source is negative, this cannot overflow to infinity.
408   if (KnownSrc.cannotBeOrderedGreaterThanZero())
409     Known.knownNot(fcPosInf);
410 
411   return Known;
412 }
