437 KnownFPClass KnownFPClass::sqrt(const KnownFPClass &KnownSrc,
438                                 DenormalMode Mode) {
439   KnownFPClass Known;
440   Known.knownNot(fcPosSubnormal);
441 
442   if (KnownSrc.isKnownNeverPosInfinity())
443     Known.knownNot(fcPosInf);
444   if (KnownSrc.isKnownNever(fcSNan))
445     Known.knownNot(fcSNan);
446 
447   // Any negative value besides -0 returns a nan.
448   if (KnownSrc.isKnownNeverNaN() && KnownSrc.cannotBeOrderedLessThanZero())
449     Known.knownNot(fcNan);
450 
451   // The only negative value that can be returned is -0 for -0 inputs.
452   Known.knownNot(fcNegInf | fcNegSubnormal | fcNegNormal);
453 
454   // If the input denormal mode could be PreserveSign, a negative
455   // subnormal input could produce a negative zero output.
456   if (KnownSrc.isKnownNeverLogicalNegZero(Mode))
457     Known.knownNot(fcNegZero);
458 
459   return Known;
460 }
