498 KnownFPClass KnownFPClass::roundToIntegral(const KnownFPClass &KnownSrc,
499                                            bool IsTrunc,
500                                            bool IsMultiUnitFPType) {
501   KnownFPClass Known;
502 
503   // Integer results cannot be subnormal.
504   Known.knownNot(fcSubnormal);
505 
506   Known.propagateNaN(KnownSrc, true);
507 
508   // Pass through infinities, except PPC_FP128 is a special case for
509   // intrinsics other than trunc.
510   if (IsTrunc || !IsMultiUnitFPType) {
511     if (KnownSrc.isKnownNeverPosInfinity())
512       Known.knownNot(fcPosInf);
513     if (KnownSrc.isKnownNeverNegInfinity())
514       Known.knownNot(fcNegInf);
515   }
516 
517   // Negative round ups to 0 produce -0
518   if (KnownSrc.isKnownNever(fcPosFinite))
519     Known.knownNot(fcPosFinite);
520   if (KnownSrc.isKnownNever(fcNegFinite))
521     Known.knownNot(fcNegFinite);
522 
523   return Known;
