527                                       DenormalMode Mode) {
528   KnownFPClass Known;
529   Known.knownNot(fcSubnormal);
530 
531   if (KnownSrc.isKnownNever(fcNegative))
532     Known.knownNot(fcNegative);
533   else {
534     if (KnownSrc.isKnownNeverLogicalNegZero(Mode))
535       Known.knownNot(fcNegZero);
536     if (KnownSrc.isKnownNever(fcNegInf))
537       Known.knownNot(fcNegInf);
538   }
539 
540   if (KnownSrc.isKnownNever(fcPositive))
541     Known.knownNot(fcPositive);
542   else {
