462 KnownFPClass KnownFPClass::fpext(const KnownFPClass &KnownSrc,
463                                  const fltSemantics &DstTy,
464                                  const fltSemantics &SrcTy) {
465   // Infinity, nan and zero propagate from source.
466   KnownFPClass Known = KnownSrc;
467 
468   // All subnormal inputs should be in the normal range in the result type.
469   if (APFloat::isRepresentableAsNormalIn(SrcTy, DstTy)) {
470     if (Known.KnownFPClasses & fcPosSubnormal)
471       Known.KnownFPClasses |= fcPosNormal;
472     if (Known.KnownFPClasses & fcNegSubnormal)
473       Known.KnownFPClasses |= fcNegNormal;
474     Known.knownNot(fcSubnormal);
475   }
476 
477   // Sign bit of a nan isn't guaranteed.
478   if (!Known.isKnownNeverNaN())
479     Known.SignBit = std::nullopt;
480 
481   return Known;
482 }
483 
484 KnownFPClass KnownFPClass::fptrunc(const KnownFPClass &KnownSrc) {
485   KnownFPClass Known;
486 
487   // Sign should be preserved
488   // TODO: Handle cannot be ordered greater than zero
489   if (KnownSrc.cannotBeOrderedLessThanZero())
490     Known.knownNot(KnownFPClass::OrderedLessThanZeroMask);
491 
492   Known.propagateNaN(KnownSrc, true);
493 
494   // Infinity needs a range check.
495   return Known;
496 }
